insert into public.faqs (category,question,answer) values
('SHIPPING','배송비는 얼마인가요?','기본 배송비는 3,000원이며 3만 원 이상 구매 시 무료배송입니다.'),
('SHIPPING','배송 기간은 얼마나 걸리나요?','평일 오후 2시 이전 결제 시 당일 출고, 평균 1~3일 내 수령 가능합니다.'),
('SHIPPING','배송 조회는 어디서 하나요?','마이페이지 > 주문내역에서 송장번호로 실시간 배송 추적이 가능합니다.'),
('RETURN','교환/반품은 어떻게 하나요?','수령 후 7일 이내, 미착용·택 미제거 상태에서 마이페이지에서 신청하실 수 있습니다.'),
('RETURN','반품 배송비가 있나요?','단순 변심 시 왕복 배송비 6,000원이 부과되며, 상품 하자 시 무료입니다.'),
('RETURN','환불은 언제 되나요?','반품 상품 회수 및 검수 완료 후 영업일 기준 3~5일 내 환불됩니다.'),
('SIZE','사이즈 추천 받을 수 있나요?','상품 상세의 "사이즈 추천" 버튼에서 키·몸무게 입력 시 최적 사이즈를 안내합니다.'),
('SIZE','운동인 체형인데 사이즈가 걱정돼요.','어깨·허벅지 발달 체형을 고려한 여유 핏 데이터를 반영합니다. 한 사이즈 업을 권장하기도 합니다.'),
('SIZE','레깅스 비침이 걱정돼요.','컴프레션 라인은 스쿼트 프루프 원단으로 비침을 최소화했습니다.');
